import json
from datetime import datetime
from elasticsearch import Elasticsearch
from elasticsearch.helpers import bulk

class EsSearchAndLogging:
    def __init__(self, host='localhost', port=9200):
        self.es = Elasticsearch([{'host': host, 'port': port, 'scheme': 'http'}])
        if not self.es.ping():
            raise ValueError("Could not connect to Elasticsearch! Make sure it's running.")
        print(f"Connected to Elasticsearch at {host}:{port}")

    def create_index(self, index_name, mappings=None, settings=None):
        if not self.es.indices.exists(index=index_name):
            index_body = {}
            if settings:
                index_body['settings'] = settings
            if mappings:
                index_body['mappings'] = mappings
            self.es.indices.create(index=index_name, body=index_body)
            print(f"Index '{index_name}' created.")
        else:
            print(f"Index '{index_name}' already exists.")

    def delete_index(self, index_name):
        if self.es.indices.exists(index=index_name):
            self.es.indices.delete(index=index_name)
            print(f"Index '{index_name}' deleted.")
        else:
            print(f"Index '{index_name}' does not exist.")

    def index_document(self, index_name, document, id_field=None):
        if id_field and id_field in document:
            doc_id = document[id_field]
            response = self.es.index(index=index_name, id=doc_id, document=document)
        else:
            response = self.es.index(index=index_name, document=document)
        print(f"Document indexed in '{index_name}' with ID: {response['_id']}")
        return response['_id']

    def bulk_index_documents(self, index_name, documents, id_field=None):
        actions = []
        for doc in documents:
            action = {
                "_index": index_name,
                "_source": doc
            }
            if id_field and id_field in doc:
                action["_id"] = doc[id_field]
            actions.append(action)
        success, failed = bulk(self.es, actions, stats_only=True)
        print(f"Bulk indexing completed. Succeeded: {success}, Failed: {failed}")
        return success, failed

    def search_documents(self, index_name, query, size=10, fields=None, sort=None):
        search_body = {
            "query": query,
            "size": size
        }
        if fields:
            search_body["_source"] = fields
        if sort:
            search_body["sort"] = sort

        response = self.es.search(index=index_name, body=search_body)
        print(f"Search results for query: {json.dumps(query, indent=2)}")
        print(f"Total hits: {response['hits']['total']['value']}")
        for hit in response['hits']['hits']:
            print(f"  ID: {hit['_id']}, Score: {hit['_score']}, Source: {json.dumps(hit['_source'], indent=2)}")
        return response['hits']['hits']

    def log_message(self, message, level='INFO', service='application', timestamp=None, **kwargs):
        log_entry = {
            "@timestamp": timestamp if timestamp else datetime.utcnow().isoformat(),
            "level": level.upper(),
            "service": service,
            "message": message,
            **kwargs
        }
        # Using a daily index for logs
        log_index_name = f"app-logs-{datetime.utcnow().strftime('%Y.%m.%d')}"
        
        # Ensure the log index exists (optional, ES can create it on first doc)
        # You might want to define a specific mapping for log indices for better search/analysis
        self.create_index(
            log_index_name,
            mappings={
                "properties": {
                    "@timestamp": {"type": "date"},
                    "level": {"type": "keyword"},
                    "service": {"type": "keyword"},
                    "message": {"type": "text"},
                    # Add other common log fields here
                }
            }
        )
        return self.index_document(log_index_name, log_entry)

    def aggregate_logs(self, index_pattern, query=None, aggregations=None, size=0):
        if not aggregations:
            aggregations = {
                "log_levels": {
                    "terms": {"field": "level.keyword"}
                },
                "service_usage": {
                    "terms": {"field": "service.keyword"}
                }
            }
        
        search_body = {
            "size": size, # We usually don't need hits for aggregations
            "aggs": aggregations
        }
        if query:
            search_body["query"] = query

        response = self.es.search(index=index_pattern, body=search_body)
        print(f"Log Aggregations for '{index_pattern}':")
        for agg_name, agg_data in response['aggregations'].items():
            print(f"  Aggregation: {agg_name}")
            if 'buckets' in agg_data:
                for bucket in agg_data['buckets']:
                    print(f"    Key: {bucket['key']}, Doc Count: {bucket['doc_count']}")
            elif 'value' in agg_data:
                 print(f"    Value: {agg_data['value']}")
        return response['aggregations']

